const https = require('https');

function fetchRSS(url, retries = 1) {
  return new Promise((resolve, reject) => {
    const options = {
      headers: {
        'User-Agent': 'Jager/1.0 (by /u/jager_developer)'
      },
      timeout: 5000
    };
    const req = https.get(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        if (res.statusCode === 200) {
          resolve(data);
        } else {
          if (retries > 0) {
            console.log(`Retrying fetch for ${url} (status ${res.statusCode})...`);
            setTimeout(() => {
              fetchRSS(url, retries - 1).then(resolve).catch(reject);
            }, 1000);
          } else {
            reject(new Error(`Status ${res.statusCode}`));
          }
        }
      });
    });
    req.on('error', (err) => {
      if (retries > 0) {
        console.log(`Retrying fetch for ${url} due to error: ${err.message}...`);
        setTimeout(() => {
          fetchRSS(url, retries - 1).then(resolve).catch(reject);
        }, 1000);
      } else {
        reject(err);
      }
    });
    req.on('timeout', () => {
      req.destroy();
      if (retries > 0) {
        console.log(`Retrying fetch for ${url} due to timeout...`);
        setTimeout(() => {
          fetchRSS(url, retries - 1).then(resolve).catch(reject);
        }, 1000);
      } else {
        reject(new Error('Request Timeout'));
      }
    });
  });
}

const results = [];
const items = $input.first().json.pages || [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const pageName = item.name;
  const feedUrl = item.feed_url;
  const pageId = item.id;
  const pageUrn = item.urn;

  if (i > 0) {
    await new Promise(resolve => setTimeout(resolve, 1000));
  }

  try {
    const xml = await fetchRSS(feedUrl);
    results.push({
      page_id: pageId,
      page_name: pageName,
      page_urn: pageUrn,
      feed_url: feedUrl,
      xml: xml
    });
  } catch (error) {
    console.error(`Error fetching feed ${pageName} (${feedUrl}):`, error.message);
  }
}
return results;

const results = [];
const items = $input.all();

let startDateStr, endDateStr;
try {
  startDateStr = $('Ingestion Date Range Parameters').first().json.start_date;
  endDateStr = $('Ingestion Date Range Parameters').first().json.end_date;
} catch (e) {
  console.log('[Parse Posts] Could not read date range from Ingestion Date Range Parameters:', e.message);
}

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const today = new Date();

let startDate = startDateStr ? new Date(startDateStr + 'T00:00:00Z') : yesterday;
let endDate = endDateStr ? new Date(endDateStr + 'T00:00:00Z') : today;

if (isNaN(startDate.getTime())) {
  startDate = yesterday;
}
if (isNaN(endDate.getTime())) {
  endDate = today;
}

for (const item of items) {
  const { page_id, page_name, page_urn, xml } = item.json;
  if (!xml) continue;

  const itemMatches = xml.match(/<item>[\s\S]*?<\/item>/g) || [];
  let matchesInFeed = 0;

  for (const entry of itemMatches) {
    const guidMatch = entry.match(/<guid[^>]*>([\s\S]*?)<\/guid>/);
    const linkMatch = entry.match(/<link>([\s\S]*?)<\/link>/);
    const creatorMatch = entry.match(/<dc:creator><!\[CDATA\[([\s\S]*?)\]\]><\/dc:creator>/) || entry.match(/<dc:creator>([\s\S]*?)<\/dc:creator>/);
    const titleMatch = entry.match(/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>/) || entry.match(/<title>([\s\S]*?)<\/title>/);
    const contentMatch = entry.match(/<content:encoded><!\[CDATA\[([\s\S]*?)\]\]><\/content:encoded>/) || entry.match(/<content:encoded>([\s\S]*?)<\/content:encoded>/) || entry.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/) || entry.match(/<description>([\s\S]*?)<\/description>/);
    const pubDateMatch = entry.match(/<pubDate>([\s\S]*?)<\/pubDate>/);

    if (guidMatch || linkMatch) {
      const id = guidMatch ? guidMatch[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/, '$1').trim() : linkMatch[1].trim();
      const url = linkMatch ? linkMatch[1].trim() : '';
      const author = page_urn;
      const title = titleMatch ? titleMatch[1].trim() : '';
      let content = contentMatch ? contentMatch[1].trim() : '';

      content = content.replace(/<[^>]*>/g, '').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&');
      if (!content) content = title;

      const published_at_raw = pubDateMatch ? pubDateMatch[1].trim() : new Date().toISOString();
      const published_at = new Date(published_at_raw);

      if (published_at >= startDate && published_at < endDate) {
        matchesInFeed++;
        results.push({
          id,
          page_id,
          page_name,
          author_urn: author,
          content: content.substring(0, 5000),
          url,
          published_at: published_at.toISOString(),
          processed: 0
        });
      }
    }
  }
  console.log(`[Parse Posts] Page: ${page_name}, matches in date range: ${matchesInFeed}`);
}
return results;
